let todolist,tododate,todoitems,dailyfocus,day=(new Date).getDay();function todoInit(){todolist=document.getElementById("todolist"),tododate=document.getElementById("tododate"),dailyfocus=document.getElementById("focus"),todoitems={monday:[["exercise","work","walk","code"],"productivity, mental health, physical health"],tuesday:[["work","walk","code"],"productivity"],wednesday:[["exercise","walk","code"],"productivity, physical health"],thursday:[["work","walk","code","write"],"productivity, mindfulness"],friday:[["walk","exercise","write"],"physical health, mindfulness"],saturday:[["clean room","write","walk","code"],"mental health, creativity, mindfulness"],sunday:[["work","walk","read","code"],"productivity, mindfulness"]},updateDay()}function updateDay(){let t=["sunday","monday","tuesday","wednesday","thursday","friday","saturday"][day],e=todoitems[t];todolist.innerHTML="",tododate.innerHTML='<span onclick="changeDay(-1);">&lt</span> '+t+' <span onclick="changeDay(1);">&gt</span>';let a=document.createDocumentFragment();for(let t=0;t<e[0].length;t++){let d=document.createElement("p");d.innerText=e[0][t],d.addEventListener("click",function(){""===d.style.textDecoration?d.style.textDecoration="line-through":d.style.textDecoration=""},!1),a.appendChild(d)}todolist.appendChild(a),dailyfocus.innerHTML="<i><u>focus:</u> "+e[1]+"</i>"}function changeDay(t){(day+=t)<0&&(day=6),day>6&&(day=0),updateDay()}todoInit();
